  1→/**
  2→ * Electron Main Process — Thin Shell
  3→ *
  4→ * Responsibilities:
  5→ * - Window lifecycle (create, show, close)
  6→ * - Backend child process management
  7→ * - IPC handler registration
  8→ * - Auto-updater setup
  9→ * - Shell environment sync (macOS PATH fix)
 10→ *
 11→ * Business logic stays in the Node.js backend and sidecar — the main process
 12→ * is purely a desktop shell that spawns them and bridges native OS features.
 13→ */
 14→
 15→import { app, BrowserWindow, ipcMain, shell } from "electron";
 16→import { join } from "path";
 17→import { is } from "@electron-toolkit/utils";
 18→import { spawnBackend, stopBackend } from "./backend-process";
 19→// Sidecar is spawned by the backend process (via SIDECAR_BUNDLE_PATH env var)
 20→import { registerNativeHandlers } from "./native-handlers";
 21→import { registerBrowserViewHandlers, destroyAllBrowserViews } from "./browser-views";
 22→// PTY, file watching, and browser server are now handled by the backend
 23→// via WebSocket commands — no Electron IPC needed for these.
 24→import { setupAutoUpdater } from "./auto-updater";
 25→import { syncShellEnvironment } from "./shell-env";
 26→
 27→// ---------------------------------------------------------------------------
 28→// Single Instance Lock
 29→// ---------------------------------------------------------------------------
 30→
 31→if (!app.requestSingleInstanceLock()) {
 32→  app.quit();
 33→  process.exit(0);
 34→}
 35→
 36→let mainWindow: BrowserWindow | null = null;
 37→
 38→// ---------------------------------------------------------------------------
 39→// Window Creation
 40→// ---------------------------------------------------------------------------
 41→
 42→async function createWindow(): Promise<void> {
 43→  mainWindow = new BrowserWindow({
 44→    width: 1400,
 45→    height: 900,
 46→    minWidth: 800,
 47→    minHeight: 600,
 48→    show: false,
 49→    titleBarStyle: process.platform === "darwin" ? "hiddenInset" : "default",
 50→    trafficLightPosition: { x: 16, y: 18 },
 51→    backgroundColor: "#00000000",
 52→    transparent: process.platform === "darwin",
 53→    vibrancy: process.platform === "darwin" ? "under-window" : undefined,
 54→    ...(process.platform === "linux"
 55→      ? { icon: join(__dirname, "../../resources/icons/icon.png") }
 56→      : {}),
 57→    webPreferences: {
 58→      preload: join(__dirname, "../preload/index.mjs"),
 59→      contextIsolation: true,
 60→      nodeIntegration: false,
 61→      sandbox: false, // ESM preload requires sandbox: false (package.json "type": "module")
 62→    },
 63→  });
 64→
 65→  // Show window once renderer is ready (avoids white flash)
 66→  mainWindow.on("ready-to-show", () => {
 67→    // Window starts hidden — the renderer calls show_main_window after
 68→    // settings/onboarding state is determined.
 69→    // Safety net: force-show after 3s if the renderer hasn't called show_main_window.
 70→    setTimeout(() => {
 71→      if (mainWindow && !mainWindow.isDestroyed() && !mainWindow.isVisible()) {
 72→        console.log("[main] Safety net: force-showing window after 3s timeout");
 73→        mainWindow.show();
 74→      }
 75→    }, 3000);
 76→  });
 77→
 78→  // Open DevTools in development
 79→  if (is.dev) {
 80→    mainWindow.webContents.openDevTools({ mode: "detach" });
 81→  }
 82→
 83→  // Forward renderer console to main process stdout (dev only — avoid leaking PII in prod logs)
 84→  if (!app.isPackaged) {
 85→    mainWindow.webContents.on("console-message", (_event, level, message, line, sourceId) => {
 86→      const prefix =
 87→        level === 2 ? "[renderer:warn]" : level === 3 ? "[renderer:error]" : "[renderer]";
 88→      const source = sourceId ? ` (${sourceId.split("/").pop()}:${line})` : "";
 89→      console.log(`${prefix} ${message}${source}`);
 90→    });
 91→  }
 92→
 93→  // External links open in system browser (only allow http/https)
 94→  mainWindow.webContents.setWindowOpenHandler(({ url }) => {
 95→    try {
 96→      const parsed = new URL(url);
 97→      if (parsed.protocol === "http:" || parsed.protocol === "https:") {
 98→        shell.openExternal(url);
 99→      }
100→    } catch {
101→      // Ignore malformed URLs
102→    }
103→    return { action: "deny" };
104→  });
105→
106→  // Block top-level navigation to external URLs (security: prevent redirect hijacks)
107→  mainWindow.webContents.on("will-navigate", (event, url) => {
108→    const appUrl = is.dev
109→      ? process.env.ELECTRON_RENDERER_URL
110→      : `file://${join(__dirname, "../renderer")}`;
111→    if (appUrl && url.startsWith(appUrl)) return; // allow app navigation
112→    event.preventDefault();
113→    try {
114→      const parsed = new URL(url);
115→      if (parsed.protocol === "http:" || parsed.protocol === "https:") {
116→        shell.openExternal(url);
117→      }
118→    } catch {
119→      /* ignore malformed */
120→    }
121→  });
122→
123→  // Track fullscreen state for CSS selectors (.fullscreen)
124→  mainWindow.on("enter-full-screen", () => {
125→    mainWindow?.webContents.send("fullscreen-change", { isFullscreen: true });
126→  });
127→  mainWindow.on("leave-full-screen", () => {
128→    mainWindow?.webContents.send("fullscreen-change", { isFullscreen: false });
129→  });
130→
131→  // Dev: load Vite dev server. Prod: load built files.
132→  if (is.dev && process.env.ELECTRON_RENDERER_URL) {
133→    mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL);
134→  } else {
135→    mainWindow.loadFile(join(__dirname, "../renderer/index.html"));
136→  }
137→}
138→
139→// ---------------------------------------------------------------------------
140→// App Lifecycle
141→// ---------------------------------------------------------------------------
142→
143→app.whenReady().then(async () => {
144→  // Debug logging to file (Electron swallows stdout/stderr in dev mode)
145→  const fs = await import("fs");
146→  const debugLogPath = join(app.getPath("temp"), "deus-debug.log");
147→  const debugLog = (msg: string) => {
148→    try {
149→      fs.appendFileSync(debugLogPath, `${new Date().toISOString()} ${msg}\n`);
150→    } catch {
151→      // Never block boot on diagnostics
152→    }
153→    console.error(msg);
154→  };
155→  debugLog("[main] App ready, starting initialization...");
156→  debugLog("[main] __dirname: " + __dirname);
157→  // Fix PATH when launched from macOS Finder (login shell doesn't run)
158→  if (process.platform === "darwin") {
159→    try {
160→      await syncShellEnvironment();
161→    } catch (err) {
162→      debugLog(
163→        "[main] syncShellEnvironment failed: " + (err instanceof Error ? err.message : String(err))
164→      );
165→    }
166→  }
167→
168→  // Spawn backend as child process
169→  debugLog("[main] Spawning backend...");
170→  try {
171→    const { port: backendPort, authToken } = await spawnBackend();
172→    debugLog("[main] Backend started on port: " + backendPort);
173→
174→    // Expose backend connection info so IPC handlers can return it to renderer
175→    process.env.DEUS_BACKEND_PORT = String(backendPort);
176→    process.env.DEUS_AUTH_TOKEN = authToken;
177→  } catch (err) {
178→    debugLog("[main] Backend spawn FAILED: " + (err instanceof Error ? err.message : String(err)));
179→    const { dialog } = await import("electron");
180→    dialog.showErrorBox(
181→      "Failed to Start",
182→      `The application backend failed to start.\n\n${err instanceof Error ? err.message : String(err)}`
183→    );
184→    app.quit();
185→    return;
186→  }
187→
188→  // Sidecar is spawned by the backend process (via SIDECAR_BUNDLE_PATH env var)
189→  // when SIDECAR_BUNDLE_PATH env var is present.
190→
191→  // Register IPC handlers before window creation so they're ready immediately
192→  registerNativeHandlers();
193→  registerBrowserViewHandlers();
194→
195→  // Cross-window event relay — when one renderer sends an event via ipcRenderer.send(),
196→  // forward it to all OTHER windows. This enables the detached browser window to
197→  // communicate with the main window (e.g., CHAT_INSERT events).
198→  const RELAY_EVENTS = new Set([
199→    "chat-insert", // Detached browser -> main window
200→    "browser-window:workspace-change", // Main window → detached browser window
201→  ]);
202→
203→  for (const channel of RELAY_EVENTS) {
204→    ipcMain.on(channel, (event, ...args) => {
205→      for (const win of BrowserWindow.getAllWindows()) {
206→        if (win.webContents.id !== event.sender.id && !win.isDestroyed()) {
207→          win.webContents.send(channel, ...args);
208→        }
209→      }
210→    });
211→  }
212→
213→  debugLog("[main] Creating window...");
214→  // PTY, FS watching, browser server — all handled by backend now
215→
216→  await createWindow();
217→  debugLog("[main] Window created");
218→
219→  // Auto-updater (delayed start — let the app boot first)
220→  if (!is.dev) {
221→    setTimeout(() => {
222→      if (mainWindow && !mainWindow.isDestroyed()) setupAutoUpdater(mainWindow);
223→    }, 15_000);
224→  }
225→});
226→
227→// Second instance: focus existing window
228→app.on("second-instance", () => {
229→  if (mainWindow) {
230→    if (mainWindow.isMinimized()) mainWindow.restore();
231→    mainWindow.focus();
232→  }
233→});
234→
235→// Quit when all windows are closed (all platforms including macOS)
236→app.on("window-all-closed", () => {
237→  app.quit();
238→});
239→
240→app.on("before-quit", () => {
241→  destroyAllBrowserViews();
242→  stopBackend();
243→});
244→
245→// Export for IPC handlers that need window reference
246→export function getMainWindow(): BrowserWindow | null {
247→  return mainWindow;
248→}
249→

