272→  // -------------------------------------------------------------------------
273→  // App detection
274→  // -------------------------------------------------------------------------
275→
276→  ipcMain.handle("native:getInstalledApps", async () => {
277→    return getInstalledAppsList();
278→  });
279→
280→  ipcMain.handle("get_installed_apps", async () => {
281→    return getInstalledAppsList();
