283→
284→  // Renderer calls invoke("open_in_app", { appId, workspacePath })
285→  // We accept both the old native: shape AND the new snake_case shape.
286→  ipcMain.handle(
287→    "native:openInApp",
288→    async (_e, { appPath, filePath }: { appPath: string; filePath: string }) => {
