362→  // Git clone is now handled by the backend via POST /api/repos/clone
363→}
364→
365→// ---- Helpers ----
366→
367→/** Curated list of apps we support in the "Open In" dropdown.
368→ * id = internal identifier (used by appIcons.tsx for categorization)
369→ * name = display name
370→ * bundleId = macOS bundle identifier for mdfind lookup */
371→const SUPPORTED_APPS = [
372→  // Editors
373→  { id: "cursor", name: "Cursor", bundleId: "com.todesktop.230313mzl4w4u92" },
374→  { id: "vscode", name: "VS Code", bundleId: "com.microsoft.VSCode" },
375→  { id: "vscode-insiders", name: "VS Code Insiders", bundleId: "com.microsoft.VSCodeInsiders" },
376→  { id: "windsurf", name: "Windsurf", bundleId: "com.exafunction.windsurf" },
377→  { id: "zed", name: "Zed", bundleId: "dev.zed.Zed" },
378→  { id: "xcode", name: "Xcode", bundleId: "com.apple.dt.Xcode" },
379→  { id: "fleet", name: "Fleet", bundleId: "com.jetbrains.fleet" },
380→  { id: "intellij", name: "IntelliJ IDEA", bundleId: "com.jetbrains.intellij" },
381→  { id: "webstorm", name: "WebStorm", bundleId: "com.jetbrains.WebStorm" },
382→  { id: "sublime", name: "Sublime Text", bundleId: "com.sublimetext.4" },
383→  // Terminals
384→  { id: "terminal", name: "Terminal", bundleId: "com.apple.Terminal" },
385→  { id: "iterm", name: "iTerm", bundleId: "com.googlecode.iterm2" },
386→  { id: "warp", name: "Warp", bundleId: "dev.warp.Warp-Stable" },
387→  // System
388→  { id: "finder", name: "Finder", bundleId: "com.apple.finder" },
389→];
390→
391→interface InstalledApp {
392→  id: string;
393→  name: string;
394→  path: string;
395→  icon?: string;
396→}
397→
398→let cachedInstalledApps: InstalledApp[] | null = null;
399→let inflightPromise: Promise<InstalledApp[]> | null = null;
400→
401→async function getInstalledAppsList(): Promise<InstalledApp[]> {
402→  if (cachedInstalledApps) return cachedInstalledApps;
403→  if (inflightPromise) return inflightPromise;
404→  if (process.platform !== "darwin") return [];
405→  inflightPromise = loadInstalledApps().finally(() => {
406→    inflightPromise = null;
407→  });
408→  return inflightPromise;
409→}
410→
411→/** Resolve icon filename from an app's Info.plist (apps use different names). */
412→async function resolveIconFileName(appPath: string): Promise<string> {
413→  try {
414→    const { stdout } = await execFileAsync("/usr/libexec/PlistBuddy", [
415→      "-c",
416→      "Print :CFBundleIconFile",
417→      `${appPath}/Contents/Info.plist`,
418→    ]);
419→    const name = stdout.trim();
420→    if (name) return name.endsWith(".icns") ? name : `${name}.icns`;
421→  } catch {
422→    // PlistBuddy failed
423→  }
424→  return "AppIcon.icns";
425→}
426→
427→/** Extract app icon as a base64 PNG data URL. */
428→async function extractAppIcon(appPath: string, appId: string): Promise<string | undefined> {
429→  try {
430→    const iconFileName = await resolveIconFileName(appPath);
431→    const icnsPath = `${appPath}/Contents/Resources/${iconFileName}`;
432→    const tmpPng = `/tmp/deus-icon-${appId}.png`;
433→    await execFileAsync("sips", [
434→      "-s",
435→      "format",
436→      "png",
437→      "-z",
438→      "64",
439→      "64",
440→      icnsPath,
441→      "--out",
442→      tmpPng,
443→    ]);
444→    const fs = await import("fs/promises");
445→    const buf = await fs.readFile(tmpPng);
446→    await fs.unlink(tmpPng).catch(() => {});
447→    return `data:image/png;base64,${buf.toString("base64")}`;
448→  } catch {
449→    return undefined;
450→  }
451→}
452→
453→async function loadInstalledApps(): Promise<InstalledApp[]> {
454→  const installed: InstalledApp[] = [];
455→
456→  for (const appDef of SUPPORTED_APPS) {
457→    try {
458→      const { stdout } = await execFileAsync("mdfind", [
459→        `kMDItemCFBundleIdentifier == '${appDef.bundleId}'`,
460→      ]);
461→      const appPath = stdout.trim().split("\n")[0];
462→      if (!appPath || !appPath.endsWith(".app")) continue;
463→
464→      const icon = await extractAppIcon(appPath, appDef.id);
465→      installed.push({ id: appDef.id, name: appDef.name, path: appPath, icon });
466→    } catch {
467→      // App not installed — skip
468→    }
469→  }
470→
471→  cachedInstalledApps = installed;
472→  return installed;
473→}
474→

