  1→/**
  2→ * Native IPC Handlers
  3→ *
  4→ * Registers ipcMain.handle() for native OS operations that the renderer
  5→ * accesses through the preload bridge.
  6→ *
  7→ * Handler names use the SAME names the renderer calls via invoke().
  8→ * The preload's generic invoke() forwards channel names unchanged, so
  9→ * snake_case names here must match the renderer exactly.
 10→ */
 11→
 12→import { ipcMain, dialog, nativeTheme, BrowserWindow, shell, Menu, app } from "electron";
 13→import { execFile } from "child_process";
 14→import { promisify } from "util";
 15→import { homedir } from "os";
 16→
 17→const execFileAsync = promisify(execFile);
 18→
 19→export function registerNativeHandlers(): void {
 20→  // -------------------------------------------------------------------------
 21→  // Window visibility
 22→  // -------------------------------------------------------------------------
 23→
 24→  ipcMain.handle("show_main_window", () => {
 25→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
 26→    if (win) {
 27→      win.show();
 28→      win.focus();
 29→    }
 30→  });
 31→
 32→  ipcMain.handle("enter_onboarding_mode", () => {
 33→    const win = BrowserWindow.getAllWindows()[0];
 34→    if (win) {
 35→      win.setBackgroundColor("#00000000");
 36→      win.show();
 37→    }
 38→  });
 39→
 40→  ipcMain.handle("exit_onboarding_mode", () => {
 41→    const win = BrowserWindow.getAllWindows()[0];
 42→    if (win) {
 43→      win.hide();
 44→    }
 45→  });
 46→
 47→  // -------------------------------------------------------------------------
 48→  // Folder picker
 49→  // -------------------------------------------------------------------------
 50→
 51→  ipcMain.handle("show_folder_dialog", async () => {
 52→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
 53→    if (!win) return null;
 54→    const result = await dialog.showOpenDialog(win, {
 55→      properties: ["openDirectory", "createDirectory"],
 56→    });
 57→    return result.canceled ? null : result.filePaths[0];
 58→  });
 59→
 60→  // Keep the native: prefixed name too — the preload's named methods
 61→  // (pickFolder, confirm, etc.) call "native:pickFolder" directly.
 62→  ipcMain.handle("native:pickFolder", async () => {
 63→    const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
 64→    if (!win) return null;
 65→    const result = await dialog.showOpenDialog(win, {
 66→      properties: ["openDirectory", "createDirectory"],
 67→    });
 68→    return result.canceled ? null : result.filePaths[0];
 69→  });
 70→
 71→  // -------------------------------------------------------------------------
 72→  // Confirm dialog
 73→  // -------------------------------------------------------------------------
 74→
 75→  ipcMain.handle(
 76→    "native:confirm",
 77→    async (_e, { message, detail }: { message: string; detail?: string }) => {
 78→      const win = BrowserWindow.getFocusedWindow() ?? BrowserWindow.getAllWindows()[0];
 79→      if (!win) return false;
 80→      const { response } = await dialog.showMessageBox(win, {
 81→        type: "question",
 82→        buttons: ["Cancel", "Confirm"],
 83→        defaultId: 1,
 84→        message,
 85→        detail,
 86→      });
 87→      return response === 1;
 88→    }
 89→  );
 90→
 91→  // -------------------------------------------------------------------------
 92→  // Theme
 93→  // -------------------------------------------------------------------------
 94→
 95→  ipcMain.handle("native:setTheme", (_e, { theme }: { theme: "light" | "dark" | "system" }) => {
 96→    nativeTheme.themeSource = theme;
 97→  });
 98→
 99→  // -------------------------------------------------------------------------
100→  // Open external URL
101→  // -------------------------------------------------------------------------
102→
103→  ipcMain.handle("native:openExternal", (_e, { url }: { url: string }) => {
104→    // Security: only allow http/https URLs to prevent shell command injection
105→    // via custom protocol handlers (e.g., file://, javascript:, vbscript:).
106→    try {
107→      const parsed = new URL(url);
108→      if (parsed.protocol === "http:" || parsed.protocol === "https:") {
109→        shell.openExternal(url);
110→      }
111→    } catch {
112→      // Ignore malformed URLs
