372→  // Editors
373→  { id: "cursor", name: "Cursor", bundleId: "com.todesktop.230313mzl4w4u92" },
374→  { id: "vscode", name: "VS Code", bundleId: "com.microsoft.VSCode" },
375→  { id: "vscode-insiders", name: "VS Code Insiders", bundleId: "com.microsoft.VSCodeInsiders" },
