import { useState, useEffect } from "react";
import { match } from "ts-pattern";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Loader2, RefreshCw, CheckCircle2, AlertCircle, Download } from "lucide-react";
import { useUpdateContext } from "@/features/updates";

export function UpdateSection() {
  const updateCtx = useUpdateContext();
  const [currentVersion, setCurrentVersion] = useState<string>("");
  const [manualChecking, setManualChecking] = useState(false);
  const [manualResult, setManualResult] = useState<"up-to-date" | null>(null);

  // Fetch current app version from Electron, fall back to Vite-injected version
  useEffect(() => {
    if (window.electronAPI) {
      window.electronAPI
        .getAppVersion()
        .then(setCurrentVersion)
        .catch(() => setCurrentVersion(__APP_VERSION__));
    } else {
      setCurrentVersion(__APP_VERSION__);
    }
  }, []);

  // Auto-dismiss "up to date" message after 3s
  useEffect(() => {
    if (manualResult !== "up-to-date") return;
    const timer = setTimeout(() => setManualResult(null), 3000);
    return () => clearTimeout(timer);
  }, [manualResult]);

  async function handleCheckForUpdates() {
    if (!updateCtx) return;
    setManualChecking(true);
    setManualResult(null);

    // check() returns true when no update is found (up to date)
    const isUpToDate = await updateCtx.check();

    setManualChecking(false);
    if (isUpToDate) {
      setManualResult("up-to-date");
    }
  }

  return (
    <div className="space-y-5">
      <div>
        <h3 className="text-base font-semibold">Updates</h3>
        <p className="text-muted-foreground mt-1 text-base">App version and update management.</p>
      </div>

      {/* Current version */}
      <div className="space-y-2">
        <Label className="text-sm">Version</Label>
        <p className="text-foreground flex items-center gap-2 font-mono text-base">
          {currentVersion ? `v${currentVersion}` : "Loading..."}
          {import.meta.env.DEV && (
            <span className="bg-warning/15 text-warning rounded px-1.5 py-0.5 text-xs font-semibold">
              DEV
            </span>
          )}
        </p>
      </div>

      <Separator />

      {/* Check for updates */}
      <div className="flex items-center justify-between">
        <div>
          <Label className="text-sm">Check for updates</Label>
          <p className="text-muted-foreground text-base">
            Updates are checked automatically every 5 minutes.
          </p>
        </div>
        <Button
          variant="outline"
          size="sm"
          onClick={handleCheckForUpdates}
          disabled={manualChecking || updateCtx?.state.stage === "downloading"}
        >
          {manualChecking ? (
            <Loader2 className="mr-1.5 size-3.5 animate-spin" />
          ) : (
            <RefreshCw className="mr-1.5 size-3.5" />
          )}
          {manualChecking ? "Checking..." : "Check now"}
        </Button>
      </div>

      {/* Status messages */}
      {updateCtx &&
        match(updateCtx.state.stage)
          .with("ready", () => (
            <div className="bg-primary/5 border-primary/20 flex items-center justify-between rounded-lg border p-3">
              <div className="flex items-center gap-2">
                <Download className="text-primary size-4" />
                <span className="text-sm">
                  Update <span className="font-semibold">v{updateCtx.state.version}</span> is ready
                </span>
              </div>
              <Button size="sm" onClick={() => void updateCtx.install()}>
                Restart to update
              </Button>
            </div>
          ))
          .with("downloading", () => (
            <div className="text-muted-foreground flex items-center gap-2 text-sm">
              <Loader2 className="size-3.5 animate-spin" />
              <span>Downloading update...</span>
            </div>
          ))
          .with("error", () => (
            <div className="text-destructive flex items-center gap-2 text-sm">
              <AlertCircle className="size-3.5" />
              <span>Update check failed: {updateCtx.state.error}</span>
            </div>
          ))
          .otherwise(() => null)}

      {/* Manual check result: up to date */}
      {manualResult === "up-to-date" && (
        <div className="text-muted-foreground flex items-center gap-2 text-sm">
          <CheckCircle2 className="text-success size-3.5" />
          <span>You're on the latest version.</span>
        </div>
      )}
    </div>
  );
}

import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import { Switch } from "@/components/ui/switch";
import { RotateCcw } from "lucide-react";
import { useUIStore } from "@/shared/stores/uiStore";
import { setAnalyticsEnabled } from "@/platform/analytics";
import { capabilities } from "@/platform";
import type { GeneralSectionProps } from "./types";

export function GeneralSection({ settings, saveSetting, theme, setTheme }: GeneralSectionProps) {
  const closeSettings = useUIStore((s) => s.closeSettings);

  return (
    <div className="space-y-5">
      <div>
        <h3 className="text-base font-semibold">General</h3>
        <p className="text-muted-foreground mt-1 text-base">
          Profile, appearance, and display preferences.
        </p>
      </div>

      {/* Name */}
      <div className="space-y-2">
        <Label htmlFor="user-name" className="text-sm">
          Name
        </Label>
        <Input
          id="user-name"
          defaultValue={settings.user_name ?? ""}
          onBlur={(e) => saveSetting("user_name", e.currentTarget.value)}
          placeholder="Your name"
        />
      </div>

      <Separator />

      {/* Theme */}
      <div className="space-y-2">
        <Label htmlFor="theme" className="text-sm">
          Theme
        </Label>
        <Select
          value={theme}
          onValueChange={(value: "light" | "dark" | "system") => setTheme(value)}
        >
          <SelectTrigger id="theme" className="w-full">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="light">Light</SelectItem>
            <SelectItem value="dark">Dark</SelectItem>
            <SelectItem value="system">System</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <Separator />

      {/* Diff view mode */}
      <div className="space-y-2">
        <Label htmlFor="diff-view" className="text-sm">
          Diff view mode
        </Label>
        <p className="text-muted-foreground text-base">
          How file changes are displayed in the diff viewer.
        </p>
        <Select
          value={settings.diff_view_mode ?? "unified"}
          onValueChange={(value) => saveSetting("diff_view_mode", value)}
        >
          <SelectTrigger id="diff-view" className="w-full">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="unified">Unified</SelectItem>
            <SelectItem value="split">Split</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <Separator />

      {/* Replay onboarding — desktop only (requires Electron window effects) */}
      {capabilities.nativeOnboarding && (
        <div className="flex items-center justify-between">
          <div>
            <Label className="text-sm">Onboarding</Label>
            <p className="text-muted-foreground text-base">Replay the setup walkthrough.</p>
          </div>
          <Button
            variant="outline"
            size="sm"
            onClick={async () => {
              const ok = await saveSetting("onboarding_completed", false);
              if (ok) closeSettings();
            }}
          >
            <RotateCcw className="mr-1.5 size-3.5" />
            Replay
          </Button>
        </div>
      )}

      <Separator />

      {/* Analytics */}
      <div className="flex items-center justify-between">
        <div>
          <Label htmlFor="analytics-toggle" className="text-sm">
            Usage analytics
          </Label>
          <p className="text-muted-foreground text-base">
            Help improve Deus by sharing anonymous usage data.
          </p>
        </div>
        <Switch
          id="analytics-toggle"
          checked={settings.analytics_enabled !== false}
          onCheckedChange={async (checked) => {
            setAnalyticsEnabled(checked);
            const ok = await saveSetting("analytics_enabled", checked);
            if (!ok) setAnalyticsEnabled(!checked);
          }}
        />
      </div>
    </div>
  );
}

/**
 * Preload Script — Main Window
 *
 * Exposes a typed API to the renderer via contextBridge.
 * This is the ONLY way the renderer communicates with the main process.
 *
 * Security: contextIsolation=true, nodeIntegration=false, sandbox=false (ESM preload requires sandbox=false).
 * The renderer has zero direct access to Node.js or Electron APIs.
 *
 * The generic invoke/on/send bridge is guarded by an allowlist so the renderer
 * cannot call arbitrary ipcMain handlers — only the channels listed below.
 */

import { contextBridge, ipcRenderer } from "electron";

// ---------------------------------------------------------------------------
// IPC channel allowlists — ONLY these channels may be used via the generic
// invoke/on/send bridge. Every channel MUST have a registered ipcMain.handle()
// or ipcMain.on() in the main process. Update these sets when adding new IPC.
// ---------------------------------------------------------------------------

const ALLOWED_INVOKE_CHANNELS = new Set([
  // Window visibility / onboarding
  "show_main_window",
  "enter_onboarding_mode",
  "exit_onboarding_mode",

  // Folder dialog (snake_case alias)
  "show_folder_dialog",

  // Backend connection
  "get_backend_port",

  // CLI / environment checks (snake_case aliases)
  "check_cli_tool",
  "check_gh_auth",
  "get_installed_apps",
  "open_in_app",

  // Browser webview management
  "create_browser_webview",
  "close_browser_webview",
  "show_browser_webview",
  "hide_browser_webview",
  "hide_all_browser_webviews",
  "set_browser_webview_bounds",
  "navigate_browser_webview",
  "reload_browser_webview",
  "eval_browser_webview",
  "eval_browser_webview_with_result",
  "screenshot_browser_webview",
  "open_browser_devtools",
  "close_browser_devtools",
  "browser:back",
  "browser:forward",

  // Browser detached windows
  "browser:createDetachedWindow",
  "browser:closeDetachedWindow",

  // Native operations (called via generic invoke from platform layer)
  "native:pickFolder",
  "native:setZoom",
  "native:setTitle",
  "native:homeDir",
]);

const ALLOWED_EVENT_CHANNELS = new Set([
  // Window state
  "fullscreen-change",

  // Backend lifecycle
  "backend:port-changed",

  // Workspace progress
  "workspace:progress",

  // File system events
  "fs:changed",

  // PTY events
  "pty-data",
  "pty-exit",

  // Browser automation events
  "browser:page-load",
  "browser:title-changed",
  "browser:url-change",
  "browser-window:workspace-change",
  "browser:detached-closed",
  "browser:keyboard-shortcut",

  // Simulator events
  "sim:build-log",

  // Chat insert events
  "chat-insert",

  // Git operations
  "git-clone-progress",

  // Auto-update state
  "update:state",
]);

const electronAPI = {
  // ---------------------------------------------------------------------------
  // Backend connection info (renderer needs this to connect WebSocket)
  // ---------------------------------------------------------------------------

  getBackendPort: (): Promise<number> => ipcRenderer.invoke("native:getBackendPort"),
  getAuthToken: (): Promise<string> => ipcRenderer.invoke("native:getAuthToken"),

  // ---------------------------------------------------------------------------
  // Native OS operations
  // ---------------------------------------------------------------------------

  pickFolder: (): Promise<string | null> => ipcRenderer.invoke("native:pickFolder"),
  confirm: (message: string, detail?: string): Promise<boolean> =>
    ipcRenderer.invoke("native:confirm", { message, detail }),
  setTheme: (theme: "light" | "dark" | "system"): Promise<void> =>
    ipcRenderer.invoke("native:setTheme", { theme }),
  openExternal: (url: string): Promise<void> => ipcRenderer.invoke("native:openExternal", { url }),
  contextMenu: (
    items: Array<{ id: string; label: string; type?: string; enabled?: boolean }>
  ): Promise<string | null> => ipcRenderer.invoke("native:contextMenu", { items }),

  // ---------------------------------------------------------------------------
  // Window visibility & control
  // ---------------------------------------------------------------------------

  showMainWindow: (): Promise<void> => ipcRenderer.invoke("native:showMainWindow"),
  enterOnboardingMode: (): Promise<void> => ipcRenderer.invoke("native:enterOnboardingMode"),
  exitOnboardingMode: (): Promise<void> => ipcRenderer.invoke("native:exitOnboardingMode"),
  minimize: (): Promise<void> => ipcRenderer.invoke("native:minimize"),
  maximize: (): Promise<void> => ipcRenderer.invoke("native:maximize"),
  close: (): Promise<void> => ipcRenderer.invoke("native:close"),
  isMaximized: (): Promise<boolean> => ipcRenderer.invoke("native:isMaximized"),
  isFullscreen: (): Promise<boolean> => ipcRenderer.invoke("native:isFullscreen"),
  toggleFullscreen: (): Promise<void> => ipcRenderer.invoke("native:toggleFullscreen"),

  // ---------------------------------------------------------------------------
  // Browser views (for agent browser automation)
  // ---------------------------------------------------------------------------

  browserInvoke: (method: string, args: unknown): Promise<unknown> =>
    ipcRenderer.invoke(`browser:${method}`, args),
  onBrowserEvent: (event: string, callback: (...args: unknown[]) => void): (() => void) => {
    const listener = (_e: Electron.IpcRendererEvent, ...args: unknown[]): void => callback(...args);
    ipcRenderer.on(event, listener);
    return () => ipcRenderer.removeListener(event, listener);
  },

  // ---------------------------------------------------------------------------
  // Auto-update
  // ---------------------------------------------------------------------------

  checkForUpdates: (): Promise<unknown> => ipcRenderer.invoke("update:check"),
  downloadUpdate: (): Promise<void> => ipcRenderer.invoke("update:download"),
  installUpdate: (): Promise<void> => ipcRenderer.invoke("update:install"),
  getUpdateState: (): Promise<unknown> => ipcRenderer.invoke("update:getState"),
  onUpdateState: (callback: (state: unknown) => void): (() => void) => {
    const listener = (_e: Electron.IpcRendererEvent, state: unknown): void => callback(state);
    ipcRenderer.on("update:state", listener);
    return () => ipcRenderer.removeListener("update:state", listener);
  },

  // ---------------------------------------------------------------------------
  // CLI / Environment checks
  // ---------------------------------------------------------------------------

  checkCliTool: (tool: string): Promise<{ installed: boolean; path: string | null }> =>
    ipcRenderer.invoke("native:checkCliTool", { tool }),
  checkGhAuth: (): Promise<{ authenticated: boolean }> => ipcRenderer.invoke("native:checkGhAuth"),
  getInstalledApps: (): Promise<Array<{ name: string; path: string }>> =>
    ipcRenderer.invoke("native:getInstalledApps"),
  openInApp: (appPath: string, filePath: string): Promise<boolean> =>
    ipcRenderer.invoke("native:openInApp", { appPath, filePath }),

  // ---------------------------------------------------------------------------
  // App info
  // ---------------------------------------------------------------------------

  getAppVersion: (): Promise<string> => ipcRenderer.invoke("native:getAppVersion"),
  getPlatform: (): Promise<string> => ipcRenderer.invoke("native:getPlatform"),

  // ---------------------------------------------------------------------------
  // Generic IPC bridge — guarded by allowlist to prevent the renderer from
  // calling arbitrary ipcMain handlers. Only channels listed in
  // ALLOWED_INVOKE_CHANNELS / ALLOWED_EVENT_CHANNELS are permitted.
  // ---------------------------------------------------------------------------

  invoke: (channel: string, args?: unknown): Promise<unknown> => {
    if (!ALLOWED_INVOKE_CHANNELS.has(channel)) {
      return Promise.reject(new Error(`IPC invoke channel "${channel}" is not allowed`));
    }
    return ipcRenderer.invoke(channel, args);
  },
  on: (event: string, callback: (...args: unknown[]) => void): (() => void) => {
    if (!ALLOWED_EVENT_CHANNELS.has(event)) {
      console.warn(`[preload] Event channel "${event}" is not allowed`);
      return () => {};
    }
    const listener = (_e: Electron.IpcRendererEvent, ...args: unknown[]): void => callback(...args);
    ipcRenderer.on(event, listener);
    return () => ipcRenderer.removeListener(event, listener);
  },
  send: (channel: string, ...args: unknown[]): void => {
    if (!ALLOWED_EVENT_CHANNELS.has(channel)) {
      console.warn(`[preload] Send channel "${channel}" is not allowed`);
      return;
    }
    ipcRenderer.send(channel, ...args);
  },

  // ---------------------------------------------------------------------------
  // Backend lifecycle (main process sends this after backend crash + restart)
  // ---------------------------------------------------------------------------

  onBackendPortChanged: (callback: (payload: { port: number }) => void): (() => void) => {
    const listener = (_e: Electron.IpcRendererEvent, payload: { port: number }): void =>
      callback(payload);
    ipcRenderer.on("backend:port-changed", listener);
    return () => ipcRenderer.removeListener("backend:port-changed", listener);
  },

  // ---------------------------------------------------------------------------
  // Fullscreen state (main process sends this on enter/leave-full-screen)
  // ---------------------------------------------------------------------------

  onFullscreenChange: (callback: (payload: { isFullscreen: boolean }) => void): (() => void) => {
    const listener = (_e: Electron.IpcRendererEvent, payload: { isFullscreen: boolean }): void =>
      callback(payload);
    ipcRenderer.on("fullscreen-change", listener);
    return () => ipcRenderer.removeListener("fullscreen-change", listener);
  },
};

contextBridge.exposeInMainWorld("electronAPI", electronAPI);

